Status DelMin_LinkList (linklist &amp;L, ElemType &amp;e){
   if(!L-&gt;next) return ERROR; //链表空，无法操作
    p=L-&gt;next; pre=L; min=p; 
     //min存储当前找到的最小值节点地址，初始为首元节点
    //pre为min的前一节点指针方便删除，初始为头结点
    //p为当前比较结点的前一结点，初始为首元节点，其后即为比较开始的结点，即链表的第二个结点
    while (p-next!=NULL)  {
        //尚存在可以比较数据的结点
         if (p-&gt;next-&gt;data&lt;min-&gt;data) { //若比较结点p-&gt;next的数据元素值小于之前找到的最小值
             pre=p; min=p-&gt;next; //将min移至p-&gt;next，将pre移至p-&gt;next的前一结点，即p
        }
        p=p-&gt;next; //否则顺着链表继续向后比较
    }
    pre-&gt;next=min-&gt;next; //循环结束确定最小值所在结点，将最小值节点从链表中拆除
    e=min-&gt;data; // 参数存储被删除的数据元素值
    free (min);  //释放空间
    return OK;
}

